from __future__ import annotations
import time, uuid
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional

class StewardRole(str, Enum):
    DOMAIN_STEWARD      = "domain_steward"
    AI_SYSTEM_STEWARD   = "ai_system_steward"
    KB_STEWARD          = "kb_steward"
    OUTPUT_REVIEWER     = "output_reviewer"
    DPO                 = "dpo"
    GOVERNANCE_LEAD     = "governance_lead"

class StewardshipScope(str, Enum):
    DOMAIN      = "domain"       # e.g. "hr", "finance", "customer"
    APPLICATION = "application"  # a specific Gen AI app
    KB          = "knowledge_base"
    ENTERPRISE  = "enterprise"

@dataclass
class StewardshipAssignment:
    assignment_id:   str = field(default_factory=lambda: str(uuid.uuid4()))
    role:            StewardRole = StewardRole.DOMAIN_STEWARD
    scope_type:      StewardshipScope = StewardshipScope.DOMAIN
    scope_id:        str = ""            # e.g. "hr" or "customer-support-rag"
    steward_email:   str = ""
    steward_name:    str = ""
    deputy_email:    Optional[str] = None  # covers absences
    assigned_utc:    float = field(default_factory=time.time)
    expires_utc:     Optional[float] = None  # None = permanent until reassigned
    is_active:       bool = True

    def is_expired(self) -> bool:
        if self.expires_utc is None:
            return False
        return time.time() > self.expires_utc

    def effective_contact(self) -> str:
        """Return the deputy if the primary is on leave (in a real system,
        this would check an HR calendar API)."""
        return self.deputy_email or self.steward_email


@dataclass
class StewardshipRegistry:
    assignments: list[StewardshipAssignment] = field(default_factory=list)

    def assign(self, assignment: StewardshipAssignment) -> None:
        # Deactivate any existing assignment for the same role + scope
        for a in self.assignments:
            if a.role == assignment.role and a.scope_id == assignment.scope_id and a.is_active:
                a.is_active = False
        self.assignments.append(assignment)

    def get_steward(self, role: StewardRole, scope_id: str) -> Optional[StewardshipAssignment]:
        for a in self.assignments:
            if a.role == role and a.scope_id == scope_id and a.is_active and not a.is_expired():
                return a
        return None

    def find_by_scope(self, scope_id: str) -> list[StewardshipAssignment]:
        return [a for a in self.assignments
                if a.scope_id == scope_id and a.is_active and not a.is_expired()]

    def coverage_gaps(self, required_roles: list[StewardRole], scope_id: str) -> list[StewardRole]:
        """Return roles with no active steward for the given scope."""
        covered = {a.role for a in self.find_by_scope(scope_id)}
        return [r for r in required_roles if r not in covered]

from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum

class OnboardingStep(str, Enum):
    POLICY_READ         = "policy_read"
    TRAINING_COMPLETE   = "training_complete"
    DASHBOARD_ACCESS    = "dashboard_access"
    COMMS_ADDED         = "comms_added"
    SHADOW_SESSION      = "shadow_session"
    SUPERVISED_APPROVAL = "supervised_approval"
    DEPUTY_ASSIGNED     = "deputy_assigned"
    COUNCIL_ATTENDED    = "council_attended"

REQUIRED_STEPS = list(OnboardingStep)

@dataclass
class StewardOnboardingRecord:
    steward_email:     str
    assignment_id:     str
    completed_steps:   list[OnboardingStep] = field(default_factory=list)

    def mark_complete(self, step: OnboardingStep) -> None:
        if step not in self.completed_steps:
            self.completed_steps.append(step)

    def is_onboarded(self) -> bool:
        return all(s in self.completed_steps for s in REQUIRED_STEPS)

    def missing_steps(self) -> list[OnboardingStep]:
        return [s for s in REQUIRED_STEPS if s not in self.completed_steps]

    def completion_pct(self) -> float:
        return round(100 * len(self.completed_steps) / len(REQUIRED_STEPS), 1)
